// Regenerates packages/cli/src/build-info.ts with the current package
// version, git SHA, dirty-tree marker, and build timestamp. Runs as a
// prebuild hook so the compiled CLI carries the real values for
// `agentops --version` (otherwise the placeholder "0.1.0" makes every
// support conversation start with "what version is this?").
//
// The generated file IS committed with placeholder values so checkouts
// work without a build. Subsequent builds rewrite it — yes, that means
// `git status` shows it as modified after every build; accepted tradeoff.

import { execSync } from "node:child_process";
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const pkgRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const pkg = JSON.parse(readFileSync(resolve(pkgRoot, "package.json"), "utf-8"));

function git(cmd) {
  try {
    return execSync(`git ${cmd}`, {
      cwd: pkgRoot,
      stdio: ["ignore", "pipe", "ignore"],
    })
      .toString()
      .trim();
  } catch {
    return "";
  }
}

const gitSha = git("rev-parse --short HEAD") || "dev";
const status = git("status --porcelain");
const dirty = status.length > 0;
const builtAt = new Date().toISOString();

const out = `// Auto-generated by scripts/write-build-info.mjs at build time.
// Do not edit by hand — \`git status\` is expected to show this file as
// modified after every build, and the next prebuild regenerates it.

export const VERSION = ${JSON.stringify(pkg.version)};
export const GIT_SHA = ${JSON.stringify(gitSha)};
export const DIRTY = ${JSON.stringify(dirty)};
export const BUILT_AT = ${JSON.stringify(builtAt)};
`;

writeFileSync(resolve(pkgRoot, "src/build-info.ts"), out);
console.log(
  `[build-info] ${pkg.version} (${gitSha}${dirty ? "-dirty" : ""}, ${builtAt})`,
);
